import React, { useState, useEffect } from "react";
import TopNavBar from "../components/TopNavBar";
import Header from "../components/Header";
import { useNavigate } from "react-router-dom";

export default function Homepage() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) {
      setDashboard({ error: "You are not logged in. Please login again." });
      setLoading(false);
      return;
    }
    fetch("http://localhost:5000/api/dashboard", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDashboard(data);
      })
      .catch(() => {
        setDashboard({ error: "Failed to fetch dashboard data." });
      })
      .finally(() => {
        setLoading(false);
      });
  }, []);

  if (loading) return <div>Loading...</div>;
  if (dashboard?.error) return <div>{dashboard.error}</div>;

  return (
    <div
      style={{ background: "#EAEDFB", minHeight: "100vh", paddingBottom: 80 }}
    >
      <Header />
      <TopNavBar />
      <div
        style={{
          maxWidth: 470,
          margin: "0 auto",
          background: "#F3F6FC",
          borderRadius: 32,
          padding: 22,
          boxShadow: "0 2px 16px #7286D340",
        }}
      >
        {/* Add your dashboard UI here as before; see previous Home page code */}
        {/* (Not included here for brevity) */}
      </div>
    </div>
  );
}
